1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCH_THRESHOLD = 5;
5	const HIGH_ENCH_RATE = 0.3;
6	const BLOCK_SIZE = 3;
7	const BLOCK_PREMIUM = 60;
8	const LOYALTY_THRESHOLD = 2;
9	const LOYALTY_RATE = 0.2;
10	const FOLLOWUP_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number };
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
26	
27	const sum = (values: number[]): number =>
28	  values.reduce((total, value) => total + value, 0);
29	
30	const sumOfBasePremiums = (items: Item[]): number =>
31	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
32	
33	const groupByType = (items: Item[]): Item[][] => {
34	  const groups: Record<string, Item[]> = {};
35	  for (const item of items) {
36	    if (!groups[item.type]) groups[item.type] = [];
37	    groups[item.type].push(item);
38	  }
39	  return Object.values(groups);
40	};
41	
42	const basePremiumForComponentGroup = (group: Item[]): number =>
43	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
44	
45	const basePremiumFor = (items: Item[]): number => {
46	  const components = items.filter(isComponent);
47	  const nonComponents = items.filter((item) => !isComponent(item));
48	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
49	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
50	};
51	
52	const surchargeFor = (
53	  items: Item[],
54	  rate: number,
55	  applies: (item: Item) => boolean,
56	): number =>
57	  sum(items.map((item) => (applies(item) ? BASE_PREMIUMS[item.type] * rate : 0)));
58	
59	const isCursed = (item: Item): boolean => item.cursed === true;
60	const isHighlyEnchanted = (item: Item): boolean =>
61	  (item.enchantment ?? 0) >= HIGH_ENCH_THRESHOLD;
62	
63	const quotePremium = (items: Item[], yearsWithMHPCO: number, quoteIndex: number): number => {
64	  const base = basePremiumFor(items);
65	  const curseSurcharge = surchargeFor(items, CURSE_RATE, isCursed);
66	  const highEnchSurcharge = surchargeFor(items, HIGH_ENCH_RATE, isHighlyEnchanted);
67	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? base * LOYALTY_RATE : 0;
68	  const followupDiscount = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
69	  return Math.ceil(base + curseSurcharge + highEnchSurcharge - loyaltyDiscount - followupDiscount + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
70	};
71	
72	export const runScenario = (scenario: any): unknown => {
73	  const yearsWithMHPCO = scenario.customer?.yearsWithMHPCO ?? 0;
74	  let quoteIndex = 0;
75	  const results = scenario.steps.map((step: any) => {
76	    const premium = quotePremium(step.items, yearsWithMHPCO, quoteIndex);
77	    quoteIndex++;
78	    return { premium };
79	  });
80	  return { results };
81	};
